1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	}
5	
6	interface QuoteStep {
7	  op: "quote";
8	  items: Item[];
9	}
10	
11	interface Scenario {
12	  customer: { yearsWithMHPCO: number };
13	  steps: QuoteStep[];
14	}
15	
16	interface QuoteResult {
17	  premium: number;
18	}
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	
23	const BASE_PREMIUM: Record<string, number> = {
24	  sword: 100,
25	  amulet: 60,
26	  staff: 80,
27	  potion: 40,
28	  rune: 25,
29	  moonstone: 25,
30	};
31	
32	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
33	const BLOCK_SIZE = 3;
34	const BLOCK_BASE_PREMIUM = 60;
35	
36	const groupBasePremium = (type: string, count: number): number => {
37	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) return BLOCK_BASE_PREMIUM;
38	  return count * BASE_PREMIUM[type];
39	};
40	
41	const countByType = (items: Item[]): Map<string, number> =>
42	  items.reduce(
43	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
44	    new Map<string, number>(),
45	  );
46	
47	const policyBase = (items: Item[]): number =>
48	  Array.from(countByType(items)).reduce(
49	    (total, [type, count]) => total + groupBasePremium(type, count),
50	    0,
51	  );
52	
53	const CURSED_RATE = 0.5;
54	
55	const itemSurcharges = (item: Item): number => {
56	  const itemBase = BASE_PREMIUM[item.type];
57	  return item.cursed ? itemBase * CURSED_RATE : 0;
58	};
59	
60	const quoteStep = ({ items }: QuoteStep): QuoteResult => {
61	  const base = policyBase(items);
62	  const surcharges = items.reduce((sum, item) => sum + itemSurcharges(item), 0);
63	  const firstInsurance = base * FIRST_INSURANCE_RATE;
64	  return { premium: Math.ceil(base + surcharges + firstInsurance + PROCESSING_FEE) };
65	};
66	
67	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
68	  const results = scenario.steps.map(quoteStep);
69	  return { results };
70	};
